UPDATE upgrade_releases
SET version = #{version}, release_type = #{releaseType}, release_notes = #{releaseNotes},
    download_url = #{downloadUrl}, platform = #{platform}, arch = #{arch},
    package_type = #{packageType}, file_name = #{fileName}, file_size = #{fileSize},
    sha256 = #{sha256}, min_version = #{minVersion}, is_active = #{isActive}
WHERE id = #{id}
